config.script:
let raw = step_2.to_string();
let data = parse_json(raw);
let entries = data.entries;

// 过滤出文件（排除目录），构建审批项
let items = [];
for entry in entries {
    if !entry.is_dir {
        let filename = entry.name;
        let is_secret = filename.contains("涉密");
        let is_compliance = filename.contains("合规");
        items.push(#{
            file: filename,
            path: entry.path,
            is_secret: is_secret,
            is_compliance: is_compliance,
            risk_level: if is_secret { "高" } else if is_compliance { "中" } else { "低" }
        });
    }
}
#{ total: items.len, items: items }

// 分析文件内容风险
let file_data = step_body_5_1.to_string();
let data = parse_json(file_data);
let content = data.content.to_lower();

let has_secret = content.contains("涉密");
let has_compliance = content.contains("合规");
let risk_score = if has_secret { 90 } else if has_compliance { 40 } else { 10 };

#{ risk_score: risk_score, has_secret: has_secret, content_length: data.size, preview: content.slice(0, 50) }

config.message:
风险等级: {{__item.risk_level}}
风险评分: {{body_script.risk_score}}分
内容预览: {{body_script.preview}}

config.script:
let raw = step_6.to_string();
let data = parse_json(raw);

let approved = 0;
let rejected = 0;
for entry in data.entries {
    if entry.is_dir { continue; }
    if entry.name.contains("approved") || entry.path.contains("approved") {
        approved += 1;
    } else {
        rejected += 1;
    }
}

// 更简单的计数方式
let total = approved + rejected;
#{ approved: approved, rejected: rejected, total: total, summary: "审批完成: " + approved.to_string() + "通过/" + rejected.to_string() + "拒绝" }

config.body:
{{step_7.summary}}
已批准目录: /tmp/wf-approval-batch/approved/
已拒绝目录: /tmp/wf-approval-batch/rejected/
